// Trigger step is a no-op for execution — initial variable context comes from
// orchestrator's buildTriggerContext(triggerPayload). This handler exists for
// consistency (every step type has a handler) but does no hydration.
// Data needs (response, survey_link, appointment, tenant) come from explicit
// get_* steps downstream — never auto-fetched here.
const item = $input.first().json;
return {
  json: {
    ...item,
    stepResult: { success: true, outputPayload: {} },
  }
};
